#include <stdio.h>
#include <string.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        char s[200005]; scanf("%s", s);
        int ones=0, curZero=0, maxZero=0;
        for(int i=0;i<N;i++){
            if(s[i]=='1'){
                ones++;
                if(curZero>maxZero) maxZero=curZero;
                curZero=0;
            }else{ // '0'
                curZero++;
            }
        }
        if(curZero>maxZero) maxZero=curZero;
        printf("%d\n", ones+maxZero);
    }
    return 0;
}

