using namespace std;
int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while(T--){
        int N; cin>>N; string s; cin>>s;
        int ones=0, curZero=0, maxZero=0;
        for(char c: s){
            if(c=='1'){
                ++ones;
                maxZero = max(maxZero, curZero);
                curZero = 0;
            }else{
                ++curZero;
            }
        }
        maxZero = max(maxZero, curZero);
        cout << ones + maxZero << '\n';
    }
    return 0;
}

