import sys

def solve():
    data = sys.stdin.read().split()
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        s = next(it).strip()
        ones = s.count('1')
        max_zero = cur = 0
        for ch in s:
            if ch == '0':
                cur += 1
            else:
                if cur > max_zero:
                    max_zero = cur
                cur = 0
        if cur > max_zero:
            max_zero = cur
        out_lines.append(str(ones + max_zero))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

